SELECT topic_name, description
FROM topics
WHERE multiple_choice_questions > (SELECT AVG(multiple_choice_questions) FROM topics);

SELECT topic_name 
FROM topics 
WHERE topic_id IN (
    SELECT topic_id 
    FROM performance_metrics 
    WHERE improvement_rate = (
        SELECT MAX(improvement_rate) 
        FROM performance_metrics
    )
);

SELECT report_id
FROM institutional_reports
WHERE improvement_rate > 2.5 AND number_of_students > 40;

SELECT user_name, role
FROM users
WHERE last_login < date('now', '-30 days');

SELECT u.user_name, u.email, r.resource_name, r.resource_url
FROM users u
INNER JOIN resources r ON u.user_id = r.created_by;

SELECT user_name, email
FROM users
WHERE role = 'student';
